#!/usr/bin/env python3
"""FED-04 idempotent applier — re-applies all edits to existing files.

Designed for the hostile shared-tree environment where parallel agents
periodically revert these files. Run this script then immediately stage
+ commit + push.
"""

import re
from pathlib import Path

ROOT = Path("/Users/jhoetter/repos/bim-ai")

# --------------------------- elements.py ---------------------------
ELEMENTS = ROOT / "app/bim_ai/elements.py"
text = ELEMENTS.read_text()
DXF_BLOCK = '''class DxfLineworkLine(BaseModel):
    """FED-04 — single straight line primitive in a DXF underlay."""

    model_config = ConfigDict(extra="ignore", populate_by_name=True)
    kind: Literal["line"] = "line"
    start: Vec2Mm
    end: Vec2Mm


class DxfLineworkPolyline(BaseModel):
    """FED-04 — open or closed polyline primitive in a DXF underlay."""

    model_config = ConfigDict(extra="ignore", populate_by_name=True)
    kind: Literal["polyline"] = "polyline"
    points: list[Vec2Mm]
    closed: bool = False


class DxfLineworkArc(BaseModel):
    """FED-04 — circular-arc primitive (centre + radius + sweep)."""

    model_config = ConfigDict(extra="ignore", populate_by_name=True)
    kind: Literal["arc"] = "arc"
    center: Vec2Mm
    radius_mm: float = Field(alias="radiusMm", gt=0)
    start_deg: float = Field(alias="startDeg")
    end_deg: float = Field(alias="endDeg")


DxfLineworkPrim = Annotated[
    DxfLineworkLine | DxfLineworkPolyline | DxfLineworkArc,
    Field(discriminator="kind"),
]


class LinkDxfElem(BaseModel):
    """FED-04 — DXF site-plan underlay attached to a host model level.

    The element holds a parsed list of 2D linework primitives (lines,
    polylines, arcs); the plan canvas renders them as a desaturated grey
    underlay on the active level so authoring snaps to the imported drawing
    without round-tripping through a shadow model. ``scale_factor`` carries
    the unit conversion the parser inferred from the DXF ``$INSUNITS``
    header so coordinates land in millimetres on import.
    """

    model_config = ConfigDict(extra="ignore", populate_by_name=True)
    kind: Literal["link_dxf"] = "link_dxf"
    id: str
    name: str = "DXF Underlay"
    level_id: str = Field(alias="levelId")
    origin_mm: Vec2Mm = Field(alias="originMm")
    rotation_deg: float = Field(default=0.0, alias="rotationDeg")
    scale_factor: float = Field(default=1.0, alias="scaleFactor", gt=0)
    linework: list[DxfLineworkPrim] = Field(default_factory=list)
    pinned: bool = Field(default=False)


'''
if "class LinkDxfElem(BaseModel):" not in text:
    text = text.replace(
        "class FamilyCatalogSource(BaseModel):",
        DXF_BLOCK + "class FamilyCatalogSource(BaseModel):",
        1,
    )
if '    "link_dxf",' not in text:
    text = text.replace(
        '    "link_model",\n    "selection_set",',
        '    "link_model",\n    "link_dxf",\n    "selection_set",',
        1,
    )
if "    | LinkDxfElem" not in text:
    text = text.replace(
        "    | LinkModelElem\n    | SelectionSetElem",
        "    | LinkModelElem\n    | LinkDxfElem\n    | SelectionSetElem",
        1,
    )
ELEMENTS.write_text(text)

# --------------------------- commands.py ---------------------------
COMMANDS = ROOT / "app/bim_ai/commands.py"
text = COMMANDS.read_text()
if "    DxfLineworkPrim,\n    EvidenceRef," not in text:
    text = text.replace(
        "    DormerRoofKind,\n    EvidenceRef,",
        "    DormerRoofKind,\n    DxfLineworkPrim,\n    EvidenceRef,",
        1,
    )
CMD_CLASS = '''class CreateLinkDxfCmd(BaseModel):
    """FED-04: create a ``link_dxf`` element from parsed DXF linework.

    Mirrors :class:`bim_ai.elements.LinkDxfElem` minus ``kind`` plus an
    optional ``id`` (the engine assigns one when omitted). The route
    handler runs ``parse_dxf_to_linework`` then dispatches this command
    through ``try_commit_bundle`` so the import is undoable.
    """

    model_config = ConfigDict(populate_by_name=True, extra="ignore")
    type: Literal["createLinkDxf"] = "createLinkDxf"
    id: str | None = None
    name: str = "DXF Underlay"
    level_id: str = Field(alias="levelId")
    origin_mm: Vec2Mm = Field(alias="originMm")
    rotation_deg: float = Field(default=0.0, alias="rotationDeg")
    scale_factor: float = Field(default=1.0, alias="scaleFactor", gt=0)
    linework: list[DxfLineworkPrim] = Field(default_factory=list)
    pinned: bool = Field(default=False)


'''
if "class CreateLinkDxfCmd(BaseModel):" not in text:
    text = text.replace(
        "# --- FED-02: selection_set + clash_test commands ----------------------------------",
        CMD_CLASS + "# --- FED-02: selection_set + clash_test commands ----------------------------------",
        1,
    )
if "| CreateLinkDxfCmd" not in text:
    text = text.replace(
        "    | DeleteLinkModelCmd\n    | UpsertSelectionSetCmd",
        "    | DeleteLinkModelCmd\n    | CreateLinkDxfCmd\n    | UpsertSelectionSetCmd",
        1,
    )
COMMANDS.write_text(text)

# --------------------------- engine.py ---------------------------
ENGINE = ROOT / "app/bim_ai/engine.py"
text = ENGINE.read_text()
if "    CreateLinkDxfCmd,\n    CreateLinkModelCmd," not in text:
    text = text.replace(
        "    CreateLevelCmd,\n    CreateLinkModelCmd,",
        "    CreateLevelCmd,\n    CreateLinkDxfCmd,\n    CreateLinkModelCmd,",
        1,
    )
if "    LinkDxfElem,\n    LinkModelElem," not in text:
    text = text.replace(
        "    LevelElem,\n    LinkModelElem,",
        "    LevelElem,\n    LinkDxfElem,\n    LinkModelElem,",
        1,
    )
CASE_BRANCH = '''        case CreateLinkDxfCmd():
            lid = cmd.id or new_id()
            if lid in els:
                raise ValueError(f"duplicate element id '{lid}'")
            if cmd.level_id not in els or not isinstance(els[cmd.level_id], LevelElem):
                raise ValueError("createLinkDxf.levelId must reference an existing Level")
            els[lid] = LinkDxfElem(
                kind="link_dxf",
                id=lid,
                name=cmd.name,
                level_id=cmd.level_id,
                origin_mm=cmd.origin_mm,
                rotation_deg=float(cmd.rotation_deg),
                scale_factor=float(cmd.scale_factor),
                linework=list(cmd.linework),
                pinned=bool(cmd.pinned),
            )

        case UpsertSelectionSetCmd():'''
if "case CreateLinkDxfCmd():" not in text:
    text = text.replace(
        "        case UpsertSelectionSetCmd():",
        CASE_BRANCH,
        1,
    )
ENGINE.write_text(text)

# --------------------------- routes_api.py ---------------------------
ROUTES = ROOT / "app/bim_ai/routes_api.py"
text = ROUTES.read_text()
ROUTE_BLOCK = '''# ---------------------------------------------------------------------------
# FED-04 — DXF underlay import
# ---------------------------------------------------------------------------


class ImportDxfBody(BaseModel):
    """FED-04: payload for ``POST /api/models/{host_id}/import-dxf``.

    Either ``file_path`` (server-side path readable by the FastAPI process)
    must be supplied. ``level_id`` names the host level the underlay is
    attached to. ``origin_mm`` / ``rotation_deg`` / ``scale_factor`` let the
    caller place the linework; defaults centre on the project origin with
    no rotation.
    """

    model_config = ConfigDict(populate_by_name=True, extra="ignore")
    file_path: str = Field(alias="filePath")
    level_id: str = Field(alias="levelId")
    name: str = Field(default="DXF Underlay")
    origin_mm: dict[str, float] | None = Field(default=None, alias="originMm")
    rotation_deg: float = Field(default=0.0, alias="rotationDeg")
    scale_factor: float = Field(default=1.0, alias="scaleFactor", gt=0)


@api_router.post("/models/{host_id}/import-dxf")
async def import_dxf(
    host_id: UUID,
    body: ImportDxfBody,
    session: AsyncSession = Depends(get_session),
    hub: Hub = Depends(get_hub),
) -> dict[str, Any]:
    """FED-04: parse a DXF file and materialise a ``link_dxf`` element.

    The route reads the file at ``body.file_path``, runs the ``ezdxf``
    parser, then dispatches a single ``createLinkDxf`` engine command on
    the host. Returns the new ``link_dxf`` element id so the frontend can
    open ManageLinksDialog with the new entry highlighted.
    """

    from pathlib import Path as _Path

    from bim_ai.dxf_import import parse_dxf_to_linework

    host_row = await load_model_row(session, host_id)
    if host_row is None:
        raise HTTPException(status_code=404, detail="Host model not found")

    dxf_path = _Path(body.file_path)
    if not dxf_path.is_file():
        raise HTTPException(
            status_code=400, detail=f"DXF file not found at filePath: {body.file_path}"
        )

    try:
        linework = parse_dxf_to_linework(dxf_path)
    except Exception as exc:
        raise HTTPException(
            status_code=400, detail=f"DXF parse failed: {exc}"
        ) from exc

    host_doc = Document.model_validate(host_row.document)
    if body.level_id not in host_doc.elements or not isinstance(
        host_doc.elements[body.level_id], LevelElem
    ):
        raise HTTPException(
            status_code=400, detail="levelId must reference an existing Level on the host model"
        )

    create_cmd = {
        "type": "createLinkDxf",
        "name": body.name,
        "levelId": body.level_id,
        "originMm": body.origin_mm or {"xMm": 0.0, "yMm": 0.0},
        "rotationDeg": float(body.rotation_deg),
        "scaleFactor": float(body.scale_factor),
        "linework": linework,
    }
    try:
        ok, new_doc, _cmds, viols, code = try_commit_bundle(host_doc, [create_cmd])
    except Exception as exc:
        raise HTTPException(status_code=400, detail=f"createLinkDxf failed: {exc}") from exc
    if not ok or new_doc is None:
        raise HTTPException(
            status_code=409,
            detail={
                "reason": code,
                "violations": [v.model_dump(by_alias=True) for v in viols],
            },
        )

    new_link_dxf_ids = [
        eid
        for eid in set(new_doc.elements.keys()) - set(host_doc.elements.keys())
        if getattr(new_doc.elements[eid], "kind", None) == "link_dxf"
    ]
    if len(new_link_dxf_ids) != 1:
        raise HTTPException(
            status_code=500,
            detail="Internal: createLinkDxf did not produce exactly one new link_dxf element",
        )
    link_element_id = new_link_dxf_ids[0]

    host_row.document = document_to_wire(new_doc)  # type: ignore[assignment]
    host_row.revision = new_doc.revision
    await session.commit()

    try:
        await hub.broadcast_json(
            host_id,
            {
                "type": "delta",
                "modelId": str(host_id),
                "revision": new_doc.revision,
            },
        )
    except Exception:
        pass

    return {
        "linkedElementId": link_element_id,
        "lineworkCount": len(linework),
    }


# ---------------------------------------------------------------------------
# AGT-01 — Agent iterate endpoint
# ---------------------------------------------------------------------------'''
